class Solution:
    def countGoodStrings(self, low: int, high: int, zero: int, one: int) -> int:
        MOD = 10**9 + 7
        max_len = high
        dp = [0] * (max_len + 1)
        dp[0] = 1

        for i in range(1, max_len + 1):
            total = 0
            if i >= zero:
                total += dp[i - zero]
            if i >= one:
                total += dp[i - one]
            dp[i] = total % MOD

        result = 0
        for l in range(low, high + 1):
            result = (result + dp[l]) % MOD

        return result

